import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { Course } from '../../models/course.model';
import { CourseService } from '../../services/course.service';

@Component({
  selector: 'app-course-list',
  templateUrl: './course-list.component.html',
  styleUrls: ['./course-list.component.css'],
})
export class CourseListComponent implements OnInit {
  courses: Course[] = [];
  filteredCourses: Course[] = [];
  searchTerm = '';
  loading = true;
  errorMessage = '';

  constructor(private courseService: CourseService, private router: Router) {}

  ngOnInit(): void {
    this.fetchCourses();
  }

  private fetchCourses(): void {
    this.loading = true;
    this.errorMessage = '';

    this.courseService.getCourses().subscribe({
      next: (courses) => {
        this.courses = courses;
        this.applyFilter();
        this.loading = false;
      },
      error: (err) => {
        this.errorMessage = 'Unable to load courses right now. Please try again.';
        console.error(err);
        this.loading = false;
      },
    });
  }

  onSearchChange(): void {
    this.applyFilter();
  }

  private applyFilter(): void {
    const term = this.searchTerm.trim().toLowerCase();
    this.filteredCourses = term
      ? this.courses.filter((c) => c.name.toLowerCase().includes(term))
      : [...this.courses];
  }

  onSelectCourse(id: number): void {
    this.router.navigate(['/courses', id]);
  }

  trackByCourseId(_index: number, course: Course): number {
    return course.id;
  }
}
<section aria-labelledby="courses-heading">
  <h1 id="courses-heading">Browse Courses</h1>

  <div class="search-row">
    <label for="search-courses" class="visually-hidden">Search courses</label>
    <input
      id="search-courses"
      type="text"
      placeholder="Search courses..."
      [(ngModel)]="searchTerm"
      (ngModelChange)="onSearchChange()"
    />
    <p class="results-count" role="status" aria-live="polite">
      {{ filteredCourses.length }} course{{ filteredCourses.length === 1 ? '' : 's' }} found
    </p>
  </div>

  <app-loading-spinner *ngIf="loading" message="Loading courses..."></app-loading-spinner>

  <p class="error-banner" *ngIf="errorMessage && !loading">{{ errorMessage }}</p>

  <div class="course-grid" *ngIf="!loading && !errorMessage">
    <app-course-card
      *ngFor="let course of filteredCourses; trackBy: trackByCourseId"
      [id]="course.id"
      [name]="course.name"
      [code]="course.code"
      [credits]="course.credits"
      [grade]="course.grade"
      (select)="onSelectCourse($event)"
    ></app-course-card>
  </div>

  <p *ngIf="!loading && !errorMessage && filteredCourses.length === 0">
    No courses found.
  </p>
</section>
